package com.interview.lld.parking.model;

// ── WHY THIS ENUM ────────────────────────────────────────────────────────────
// The vocabulary of spot sizes. The "rank" field is the whole trick: a bigger
// number means a bigger spot. That single int lets the "does this spot fit this
// vehicle" check be one comparison instead of a pile of if/else branches.
// 🎙️ "I give each size a rank. A vehicle fits a spot when the spot's rank is at
//      least the vehicle's required rank. One number, one comparison, done."
public enum SpotSize {
    // WHY: order matters — COMPACT < LARGE. The rank encodes "how big".
    COMPACT(1),
    LARGE(2),
    // WHY: HANDICAPPED is its own size, not "bigger/smaller". A handicapped
    //      vehicle needs a HANDICAPPED spot exactly; a normal car must NOT take
    //      one. So we treat it as a separate bucket, matched by exact equality,
    //      not by the rank ordering. See VehicleType.fits().
    HANDICAPPED(0);

    private final int rank;

    SpotSize(int rank) {
        this.rank = rank;
    }

    public int rank() {
        return rank;
    }
}

package com.interview.lld.parking.model;

// ── WHY THIS ENUM ────────────────────────────────────────────────────────────
// What kind of vehicle is parking, and which spot sizes it is allowed to use.
// The "fits" rule lives HERE (on the vehicle type) instead of being scattered
// across the service, so there is exactly ONE place that decides compatibility.
// 🎙️ "Each vehicle type knows which spots it can use. A motorcycle fits a
//      compact or a large. A car needs at least a large. A handicapped vehicle
//      needs a handicapped spot exactly. The rule is one method, right here."
public enum VehicleType {
    MOTORCYCLE(SpotSize.COMPACT),
    CAR(SpotSize.LARGE),
    HANDICAPPED(SpotSize.HANDICAPPED);

    // WHY: the smallest spot size this vehicle is allowed to occupy.
    private final SpotSize minSize;

    VehicleType(SpotSize minSize) {
        this.minSize = minSize;
    }

    public SpotSize minSize() {
        return minSize;
    }

    // WHY: one rule for "can this vehicle use this spot". HANDICAPPED is a
    //      special bucket — it must match exactly, both ways, so a normal car
    //      can never steal a handicapped spot and a handicapped vehicle can
    //      never be parked in a normal spot. Everything else is the rank test:
    //      the spot must be at least as big as the vehicle needs.
    // ⚠️ FOLLOW-UP: "Why not just compare ranks for everything?"
    //    → "Because handicapped isn't 'bigger' or 'smaller' — it's a reserved
    //       category. Pure rank comparison would let a regular car grab a
    //       handicapped spot, which is exactly what we must prevent."
    public boolean fits(SpotSize spotSize) {
        if (this == HANDICAPPED || spotSize == SpotSize.HANDICAPPED) {
            return this == HANDICAPPED && spotSize == SpotSize.HANDICAPPED;
        }
        return spotSize.rank() >= minSize.rank();
    }
}

package com.interview.lld.parking.model;

// ── WHY THIS ENUM ────────────────────────────────────────────────────────────
// The two states a spot can be in. We keep it deliberately tiny — a spot is
// either free to take or already taken. No "RESERVED" middle state in v1: a
// park is one step, not a hold-then-confirm flow.
// 🎙️ "A spot is just FREE or OCCUPIED. There's no reservation step here — you
//      either grab it or you don't. If we added online pre-booking later, I'd
//      add a RESERVED state and the same state-machine guard would cover it."
public enum SpotStatus {
    FREE,
    OCCUPIED
}

package com.interview.lld.parking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The single base type for every error this system throws. Callers can catch
// ParkingException to handle "anything the parking lot rejected" in one place,
// or catch a specific subclass for a specific failure. We never throw a bare
// RuntimeException from our own code — every failure has a named type.
// 🎙️ "All my errors extend one base, ParkingException. That way a caller can
//      catch the whole family or one specific case. No naked exceptions."
public class ParkingException extends RuntimeException {
    public ParkingException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Thrown when a vehicle tries to park but no compatible spot is free anywhere
// in the lot. This is the "lot full" path — a first-class, named outcome, NOT
// a returned null that the caller might forget to check.
// 🎙️ "If the lot is full for this vehicle's size, I throw a typed error, not
//      return null. A null return is the classic bug — the caller forgets to
//      check it and parks a ghost car. A thrown error can't be ignored."
public class NoSpotAvailableException extends ParkingException {
    public NoSpotAvailableException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Thrown when someone tries to unpark with a ticket id the system has never
// issued (or already closed out). It is the "unknown id" boundary check on the
// unpark path.
// 🎙️ "Unpark validates the ticket id first. A bad or already-used ticket gets
//      a clear typed error before we touch any spot state."
public class TicketNotFoundException extends ParkingException {
    public TicketNotFoundException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Thrown by the spot's own state machine when someone asks for an illegal
// transition — e.g. occupying a spot that is already occupied. This is how the
// spot protects its own rule "a free spot can only be occupied once".
// 🎙️ "The spot itself rejects illegal moves. If two writes somehow both try to
//      occupy the same free spot, the second one hits this error instead of
//      silently overwriting the first car. The state machine is the last line
//      of defense behind the lock."
public class InvalidSpotStateException extends ParkingException {
    public InvalidSpotStateException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

import java.util.Objects;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// A vehicle that wants to park. It is a value object — a plate plus a type —
// that never changes after it is created. We model it as a record so it is
// immutable for free and gets equals/hashCode automatically.
// 🎙️ "Vehicle is just a license plate and a type. It's immutable — once you
//      hand me a vehicle, nothing about it changes. A record gives me that and
//      value-equality without boilerplate."
public record Vehicle(String licensePlate, VehicleType type) {

    // WHY: validate at the boundary — a vehicle with no plate or no type is
    //      nonsense and we reject it the moment it is built, before it can flow
    //      into park() and corrupt anything downstream.
    public Vehicle {
        Objects.requireNonNull(licensePlate, "licensePlate must not be null");
        Objects.requireNonNull(type, "type must not be null");
        if (licensePlate.isBlank()) {
            throw new ParkingException("licensePlate must not be blank");
        }
    }
}

package com.interview.lld.parking.model;

import java.util.concurrent.locks.ReentrantLock;

import javax.annotation.Nullable;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// One physical parking spot. This is the heart of the design and the heart of
// the concurrency story. Two ideas live here:
//   1. The spot is a tiny STATE MACHINE — it is the ONLY thing allowed to flip
//      its own status FREE <-> OCCUPIED. The service never writes status
//      directly, so an illegal jump is impossible by construction.
//   2. The spot carries its OWN lock. To park, you must hold THIS spot's lock.
//      Two threads grabbing two DIFFERENT spots never block each other — there
//      is no global lock and no global bottleneck. The lock is fine-grained,
//      one per spot.
// 🎙️ "Each spot owns its status AND its own lock. To take a spot you lock that
//      one spot, check it's free, occupy it, unlock. Two cars going for two
//      different spots run fully in parallel — the only time anyone waits is
//      when two cars fight over the exact same spot, and then the lock makes
//      one of them lose cleanly."
public class ParkingSpot {

    private final String id;
    private final int floorNumber;
    private final SpotSize size;

    // WHY: physical state lives on the spot — "what is in this spot right now"
    //      is the spot's own condition, not a relationship the service tracks.
    private SpotStatus status;

    // WHY: who is parked here. Null when FREE. Lets unpark confirm we are
    //      freeing the right car and lets the demo print what was parked.
    @Nullable
    private Vehicle vehicle;

    // WHY: the per-spot lock. This is the whole concurrency mechanism — each
    //      spot has its own ReentrantLock, so locking is fine-grained. We
    //      expose lock()/unlock() so the thread-safe service can wrap the
    //      check-and-occupy as one atomic step. The clean service never calls
    //      these; only the ThreadSafe subclass does.
    private final ReentrantLock lock = new ReentrantLock();

    public ParkingSpot(String id, int floorNumber, SpotSize size) {
        this.id = id;
        this.floorNumber = floorNumber;
        this.size = size;
        this.status = SpotStatus.FREE;
        this.vehicle = null;
    }

    public String id() {
        return id;
    }

    public int floorNumber() {
        return floorNumber;
    }

    public SpotSize size() {
        return size;
    }

    public SpotStatus status() {
        return status;
    }

    public boolean isFree() {
        return status == SpotStatus.FREE;
    }

    @Nullable
    public Vehicle vehicle() {
        return vehicle;
    }

    public ReentrantLock lock() {
        return lock;
    }

    // WHY: the only way to put a car in a spot. We guard the transition: a spot
    //      that is already OCCUPIED cannot be occupied again. If that guard
    //      ever fires, it means two writers reached the same free spot — the
    //      lock is supposed to prevent that, so this is the state machine
    //      catching a bug the lock missed.
    // ⚠️ FOLLOW-UP: "Isn't this redundant with the lock?"
    //    → "It's belt and suspenders. The lock makes the race impossible; the
    //       state guard makes a logic bug LOUD instead of silent. If someone
    //       refactors the lock away, this throws instead of overwriting a car."
    public void occupy(Vehicle v) {
        if (status != SpotStatus.FREE) {
            throw new InvalidSpotStateException(
                "spot " + id + " is not FREE, cannot occupy");
        }
        this.status = SpotStatus.OCCUPIED;
        this.vehicle = v;
    }

    // WHY: free the spot. Idempotent on purpose — calling it on an already-FREE
    //      spot does nothing rather than throwing. That keeps unpark and any
    //      future cleanup sweep safe to call without first re-checking state.
    // ⚠️ FOLLOW-UP: "Why is releasing twice a no-op instead of an error?"
    //    → "Because two cleanup paths could both try to free the same spot —
    //       a real unpark and a stale-ticket sweep. Whoever frees it first
    //       wins, the second call quietly does nothing. No spurious error on a
    //       perfectly correct double-free."
    public void release() {
        // WHY: only flip if currently occupied; otherwise leave it alone.
        if (status == SpotStatus.OCCUPIED) {
            this.status = SpotStatus.FREE;
            this.vehicle = null;
        }
    }

    @Override
    public String toString() {
        return "Spot{" + id + ", floor=" + floorNumber + ", " + size
            + ", " + status + "}";
    }
}

package com.interview.lld.parking.model;

import java.time.Instant;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The receipt handed back when a car parks. It pins down everything we need to
// charge correctly at exit: which spot, which vehicle, and the exact moment
// parking started. It is immutable — a ticket, once issued, never changes — so
// it is a record. The fee is NOT stored on the ticket because it is unknown at
// entry; it is computed at exit from entryTime and the exit time.
// 🎙️ "The ticket is the entry receipt. It remembers the spot, the vehicle and
//      the entry timestamp. I deliberately do NOT store the price here — we
//      don't know it yet at entry. The price is computed at exit from how long
//      the car stayed."
public record Ticket(String id, String spotId, Vehicle vehicle, Instant entryTime) {
    public Ticket {
        if (id == null || spotId == null || vehicle == null || entryTime == null) {
            throw new ParkingException("ticket fields must not be null");
        }
    }
}

package com.interview.lld.parking.model;

import java.util.ArrayList;
import java.util.List;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// One floor of the lot. It OWNS its spots — kill the floor and its spots go
// with it (composition). A floor is mostly a labelled bag of spots; the
// interesting allocation logic lives in the Strategy, not here. We give it a
// number so "nearest spot" can mean "lowest floor first".
// 🎙️ "A floor just owns its list of spots and knows its floor number. It's a
//      container. I keep the spots here so the strategy can ask each floor for
//      its spots in order — lower floors are 'nearer' to the entrance."
public class ParkingFloor {

    private final int floorNumber;
    private final List<ParkingSpot> spots;

    public ParkingFloor(int floorNumber, List<ParkingSpot> spots) {
        this.floorNumber = floorNumber;
        // WHY: defensive copy — the floor owns its spots and no outsider can
        //      mutate the list out from under it after construction.
        this.spots = new ArrayList<>(spots);
    }

    public int floorNumber() {
        return floorNumber;
    }

    // WHY: hand back an unmodifiable view. Callers (the strategy) read it to
    //      scan for a free spot, but they can't add or remove spots.
    public List<ParkingSpot> spots() {
        return List.copyOf(spots);
    }
}

package com.interview.lld.parking.strategy;

import java.util.List;
import java.util.Optional;

import com.interview.lld.parking.model.ParkingFloor;
import com.interview.lld.parking.model.VehicleType;

// ── WHY THIS INTERFACE ───────────────────────────────────────────────────────
// The extensibility seam. The lot does NOT hardcode how to pick a spot — it
// asks a strategy. Today the policy is "best fit, nearest floor". Tomorrow the
// business might want "cheapest category first" or "spread cars across floors".
// Each new policy is a new class implementing this interface; the service never
// changes. This is the Strategy pattern and the one smart move for this problem.
// 🎙️ "Picking a spot is a policy decision, so I pull it out behind an
//      interface. The lot asks 'strategy, find me a spot for this vehicle'. To
//      change the rule — random, cheapest-first, best-fit — I add one class.
//      The lot's core code never moves."
public interface SpotAllocationStrategy {

    // WHY: returns an Optional, not null — "no spot" is a real, explicit answer
    //      the caller must unwrap, not a null that slips through. The service
    //      turns an empty Optional into a typed NoSpotAvailableException.
    // WHY: takes the floors and the vehicle type; the strategy decides which
    //      spot is best WITHOUT knowing anything about tickets, fees or locks.
    //      It returns only a CANDIDATE — the service still locks and confirms.
    Optional<com.interview.lld.parking.model.ParkingSpot> findSpot(
        List<ParkingFloor> floors, VehicleType vehicleType);
}

package com.interview.lld.parking.strategy;

import java.util.Comparator;
import java.util.List;
import java.util.Optional;

import com.interview.lld.parking.model.ParkingFloor;
import com.interview.lld.parking.model.ParkingSpot;
import com.interview.lld.parking.model.SpotSize;
import com.interview.lld.parking.model.VehicleType;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The default policy: among all free, compatible spots, pick the SMALLEST that
// still fits (best fit), breaking ties by nearest floor then spot id. Best fit
// avoids wasting a large spot on a motorcycle when a compact would do, so big
// spots stay available for the cars that actually need them.
// 🎙️ "Best fit means: don't burn a large spot on a motorcycle if a compact is
//      free. I sort candidates by spot size first, then by floor — lowest
//      floor is nearest the entrance — then by id for a stable, deterministic
//      pick. The first one in that order wins."
public class BestFitNearestStrategy implements SpotAllocationStrategy {

    // WHY: order candidates so the BEST one is first:
    //   1. smallest fitting size (best fit — don't waste big spots)
    //   2. lowest floor (nearest the entrance)
    //   3. spot id (deterministic tie-break so the same input always picks the
    //      same spot — makes tests reproducible)
    private static final Comparator<ParkingSpot> BEST_FIRST =
        Comparator.comparingInt((ParkingSpot s) -> s.size().rank())
            .thenComparingInt(ParkingSpot::floorNumber)
            .thenComparing(ParkingSpot::id);

    @Override
    public Optional<ParkingSpot> findSpot(List<ParkingFloor> floors, VehicleType vehicleType) {
        // WHY: flatten every floor's spots, keep only the ones that are free
        //      AND compatible with this vehicle, then take the best by the
        //      comparator above. A single stream expresses the whole policy.
        // ⚠️ FOLLOW-UP: "Isn't scanning every spot slow?"
        //    → "It's O(total spots), but a real lot is a few hundred spots, so
        //       a scan is microseconds. If a lot grew to tens of thousands of
        //       spots I'd keep a per-size free-list or a heap per size; I'd
        //       flip to that around a few thousand spots. At this scale the
        //       scan is simpler and just as fast."
        return floors.stream()
            .flatMap(floor -> floor.spots().stream())
            .filter(ParkingSpot::isFree)
            .filter(spot -> isCompatible(spot.size(), vehicleType))
            .min(BEST_FIRST);
    }

    // WHY: compatibility lives on VehicleType.fits — we just call it here so
    //      there is exactly one definition of "does this vehicle fit this
    //      spot" in the whole system.
    private boolean isCompatible(SpotSize spotSize, VehicleType vehicleType) {
        return vehicleType.fits(spotSize);
    }
}

package com.interview.lld.parking.service;

import java.time.Duration;
import java.time.Instant;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.function.Supplier;

import com.interview.lld.parking.model.NoSpotAvailableException;
import com.interview.lld.parking.model.ParkingFloor;
import com.interview.lld.parking.model.ParkingSpot;
import com.interview.lld.parking.model.Ticket;
import com.interview.lld.parking.model.TicketNotFoundException;
import com.interview.lld.parking.model.Vehicle;
import com.interview.lld.parking.strategy.SpotAllocationStrategy;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The brain — the public API external code calls. It owns the floors, the
// open-ticket registry, and the clock and rate used to bill. It coordinates:
// it asks the strategy WHICH spot, then occupies it and issues a ticket; on
// exit it frees the spot and computes the fee. It does NOT decide which spot is
// best (that's the strategy) and it does NOT flip spot status directly (that's
// the spot's own state machine).
//
// This is the CLEAN, single-threaded-correct core: there is NOT one line of
// lock code in this file. The only seam is the withSpotGuard() hook — a
// do-nothing wrapper here that the thread-safe subclass overrides with a real
// per-spot lock. (This is the Template Method move.)
// 🎙️ "This is the orchestrator. It holds the floors and a map of open tickets.
//      Park = ask the strategy for a spot, occupy it, issue a ticket. Unpark =
//      look up the ticket, free the spot, compute the fee. Notice there are
//      zero locks in this file — concurrency is a separate subclass that
//      overrides one tiny hook."
public class ParkingLotService {

    private final List<ParkingFloor> floors;
    private final SpotAllocationStrategy strategy;

    // WHY: time is injected as a Supplier instead of calling Instant.now()
    //      inside the code. Tests pass a fake clock so we can "pretend the car
    //      stayed two hours" without actually waiting two hours.
    private final Supplier<Instant> clock;

    // WHY: the hourly rate, in cents, used to bill at exit. Cents (an int-like
    //      long) avoids floating-point money bugs.
    private final long ratePerHourCents;

    // WHY: the open-ticket registry — the orchestrator owns the truth about
    //      every car currently parked. ConcurrentHashMap so the thread-safe
    //      subclass can read/write it from many threads without a separate map
    //      lock; the clean core treats it as a plain map. Key is the spot id,
    //      so unpark can find and free the exact spot in O(1).
    private final Map<String, Ticket> openTickets = new ConcurrentHashMap<>();

    // WHY: a counter for ticket ids (tkt-1, tkt-2...) instead of random UUIDs.
    //      Numbered ids make test assertions readable. Production would swap in
    //      a UUID. AtomicLong so id generation is safe under the subclass too.
    private final AtomicLong ticketCounter = new AtomicLong(0);

    public ParkingLotService(List<ParkingFloor> floors,
                             SpotAllocationStrategy strategy,
                             Supplier<Instant> clock,
                             long ratePerHourCents) {
        this.floors = List.copyOf(floors);
        this.strategy = strategy;
        this.clock = clock;
        this.ratePerHourCents = ratePerHourCents;
    }

    // ─── Template Method HOOK ────────────────────────────────────────────────
    // WHY: this wrapper does NOTHING in the clean version — it just runs the
    //      action. The thread-safe subclass overrides it to lock THIS spot
    //      around the action. Result: this whole file has no lock code, and the
    //      concurrency diff is one overridden method.
    // 🎙️ "This hook is the seam. Here it just runs the work. The thread-safe
    //      subclass overrides it to take the spot's own lock first. My clean
    //      code never mentions locks."
    protected <T> T withSpotGuard(ParkingSpot spot, Supplier<T> action) {
        return action.get();
    }

    // ─── PARK ────────────────────────────────────────────────────────────────
    // WHY: the pipeline — find, then occupy-and-ticket as one guarded step.
    //   1. ask the strategy for the best free, compatible spot
    //   2. if none, throw the typed "lot full" error (never return null)
    //   3. under the spot guard: re-check it's free, occupy it, issue a ticket
    //   4. record the ticket in the registry and return it
    // The re-check inside the guard is what makes park race-safe in the
    // subclass: between step 1 and step 3 another thread could have taken the
    // spot, so we look again while holding the lock.
    public Ticket park(Vehicle vehicle) {
        if (vehicle == null) {
            throw new com.interview.lld.parking.model.ParkingException(
                "vehicle must not be null");
        }

        ParkingSpot candidate = strategy.findSpot(floors, vehicle.type())
            .orElseThrow(() -> new NoSpotAvailableException(
                "no free spot for vehicle type " + vehicle.type()));

        // WHY: the critical section is "confirm free + occupy + ticket". In the
        //      clean core the guard is a no-op so this just runs. In the
        //      subclass it runs while holding candidate's lock, so no two
        //      threads can both occupy the same spot.
        return withSpotGuard(candidate, () -> {
            // WHY: re-check INSIDE the guard. The strategy's answer is a hint
            //      that may be stale by the time we hold the lock. If the spot
            //      was taken meanwhile, retry the whole park once.
            if (!candidate.isFree()) {
                return park(vehicle);
            }
            candidate.occupy(vehicle);
            Ticket ticket = new Ticket(
                nextTicketId(), candidate.id(), vehicle, clock.get());
            openTickets.put(candidate.id(), ticket);
            return ticket;
        });
    }

    // ─── UNPARK ──────────────────────────────────────────────────────────────
    // WHY: the completion path — look up, guard, free, bill.
    //   1. look up the open ticket by id; unknown id -> typed error
    //   2. find the spot the ticket points at
    //   3. under the spot guard: free the spot and drop the ticket
    //   4. compute and return the fee from entry time to now
    public long unpark(String ticketId) {
        if (ticketId == null) {
            throw new TicketNotFoundException("ticketId must not be null");
        }

        // WHY: tickets are keyed by spot id in the registry, but callers hold a
        //      ticket id, so we scan the small open-ticket set to find it. The
        //      open set is bounded by the number of currently parked cars.
        Ticket ticket = findOpenTicketById(ticketId);
        if (ticket == null) {
            throw new TicketNotFoundException(
                "no open ticket with id " + ticketId);
        }

        ParkingSpot spot = findSpotById(ticket.spotId());

        withSpotGuard(spot, () -> {
            spot.release();
            // WHY: drop from the registry so the same ticket can't be unparked
            //      twice and the spot id is free to be re-keyed by a new park.
            openTickets.remove(spot.id());
            return null;
        });

        return computeFee(ticket.entryTime(), clock.get());
    }

    // ─── QUERIES ─────────────────────────────────────────────────────────────
    // WHY: how many spots are currently taken. Reads the registry size in O(1)
    //      — the registry IS the set of occupied spots, so no scanning.
    public int occupiedCount() {
        return openTickets.size();
    }

    // WHY: count free spots compatible with a vehicle type — used by the demo
    //      and tests to confirm the lot drains and refills correctly.
    public long availableCountFor(
            com.interview.lld.parking.model.VehicleType type) {
        return floors.stream()
            .flatMap(f -> f.spots().stream())
            .filter(ParkingSpot::isFree)
            .filter(s -> type.fits(s.size()))
            .count();
    }

    // ─── HELPERS ─────────────────────────────────────────────────────────────
    // WHY: generate the next readable ticket id. Atomic so even the subclass's
    //      many threads each get a distinct id.
    private String nextTicketId() {
        return "tkt-" + ticketCounter.incrementAndGet();
    }

    // WHY: scan the open tickets for the one with this id. The set is small
    //      (only currently-parked cars), so the scan is cheap. We key the map
    //      by spot id for O(1) unpark-by-spot, and accept O(open) for the
    //      by-ticket-id lookup since the open set is bounded by lot capacity.
    private Ticket findOpenTicketById(String ticketId) {
        for (Ticket t : openTickets.values()) {
            if (t.id().equals(ticketId)) {
                return t;
            }
        }
        return null;
    }

    // WHY: locate the physical spot a ticket refers to. If the spot id on a
    //      live ticket has no matching spot, the lot config is corrupt — a
    //      typed error beats a silent null.
    private ParkingSpot findSpotById(String spotId) {
        for (ParkingFloor floor : floors) {
            for (ParkingSpot spot : floor.spots()) {
                if (spot.id().equals(spotId)) {
                    return spot;
                }
            }
        }
        throw new TicketNotFoundException(
            "ticket points at unknown spot " + spotId);
    }

    // WHY: bill by the hour, rounding any partial hour UP — standard parking
    //      practice. A 61-minute stay bills two hours. Done in cents to avoid
    //      floating-point money errors. Minimum one hour for any stay.
    // ⚠️ FOLLOW-UP: "Why round up?"
    //    → "Real lots bill per started hour — five minutes over still costs the
    //       next hour. Rounding up is the correct domain behavior, and it also
    //       guarantees every stay bills at least the one-hour minimum."
    private long computeFee(Instant entry, Instant exit) {
        Duration stay = Duration.between(entry, exit);
        long minutes = Math.max(0, stay.toMinutes());
        long hours = (minutes + 59) / 60;     // round up partial hours
        if (hours == 0) {
            hours = 1;                         // minimum one hour
        }
        return hours * ratePerHourCents;
    }
}

package com.interview.lld.parking.service;

import java.time.Instant;
import java.util.List;
import java.util.concurrent.locks.ReentrantLock;
import java.util.function.Supplier;

import com.interview.lld.parking.model.ParkingFloor;
import com.interview.lld.parking.model.ParkingSpot;
import com.interview.lld.parking.strategy.SpotAllocationStrategy;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The thread-safe version. It changes EXACTLY ONE thing: it overrides the
// withSpotGuard hook to take the spot's OWN lock around the check-and-occupy.
// Every other line of behavior is inherited unchanged from the clean service.
// The diff between "clean" and "thread-safe" is this one method.
//
// PER-SPOT FINE-GRAINED LOCKS: each ParkingSpot carries its own ReentrantLock.
// park() locks that one spot before marking it occupied, so two threads can
// never both occupy the same spot — that's the double-allocation race, gone.
// Two threads parking in DIFFERENT spots take DIFFERENT locks, so they run
// fully in parallel — no global bottleneck.
// 🎙️ "Thread safety is one overridden method. I lock the spot we're about to
//      take, not a global lock. Two cars going for two different spots never
//      wait on each other — they hold different locks. Only two cars fighting
//      over the SAME spot serialize, and the loser sees it's taken and the
//      re-check in park() sends it to find another spot."
public class ThreadSafeParkingLotService extends ParkingLotService {

    public ThreadSafeParkingLotService(List<ParkingFloor> floors,
                                       SpotAllocationStrategy strategy,
                                       Supplier<Instant> clock,
                                       long ratePerHourCents) {
        super(floors, strategy, clock, ratePerHourCents);
    }

    // ─── The ONLY override ───────────────────────────────────────────────────
    // WHY: take the spot's own lock, run the action, always unlock. A
    //      ReentrantLock so the same thread can safely re-enter if a guarded
    //      method ever calls another guarded method on the same spot. The
    //      lock/try/finally is the textbook safe pattern — unlock always runs,
    //      even if the action throws.
    // ⚠️ FOLLOW-UP: "Why per-spot locks and not one lock for the whole lot?"
    //    → "One global lock is correct but kills throughput — every park in the
    //       whole building serializes through one bottleneck. Per-spot locks
    //       let a hundred cars park into a hundred different spots at once. Only
    //       two cars contending for the same spot ever wait, and that wait is
    //       microseconds."
    @Override
    protected <T> T withSpotGuard(ParkingSpot spot, Supplier<T> action) {
        ReentrantLock lock = spot.lock();
        lock.lock();
        try {
            return action.get();
        } finally {
            lock.unlock();
        }
    }
}

package com.interview.lld.parking;

import java.time.Duration;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CyclicBarrier;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

import com.interview.lld.parking.model.NoSpotAvailableException;
import com.interview.lld.parking.model.ParkingFloor;
import com.interview.lld.parking.model.ParkingSpot;
import com.interview.lld.parking.model.SpotSize;
import com.interview.lld.parking.model.Ticket;
import com.interview.lld.parking.model.TicketNotFoundException;
import com.interview.lld.parking.model.Vehicle;
import com.interview.lld.parking.model.VehicleType;
import com.interview.lld.parking.service.ParkingLotService;
import com.interview.lld.parking.service.ThreadSafeParkingLotService;
import com.interview.lld.parking.strategy.BestFitNearestStrategy;

// Java 17+
// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The demo driver. It exercises the tricky cases the interviewer cares about:
// a happy park+unpark with a real fee, best-fit picking the smallest spot, the
// lot-full rejection, an unknown-ticket rejection, and a real concurrency
// stampede proving no two threads ever get the same spot.
public class Main {

    public static void main(String[] args) throws Exception {
        // A mutable fake clock so we can fast-forward time without sleeping.
        Instant[] now = { Instant.parse("2026-06-21T08:00:00Z") };

        // Case 1 — happy path: park a car, fast-forward 90 minutes, unpark, fee.
        {
            ParkingLotService lot = new ParkingLotService(
                buildLot(), new BestFitNearestStrategy(), () -> now[0], 200);
            Vehicle car = new Vehicle("CAR-1", VehicleType.CAR);
            Ticket t = lot.park(car);
            now[0] = now[0].plus(Duration.ofMinutes(90));   // 90 min -> bills 2h
            long fee = lot.unpark(t.id());
            assertTrue(t.spotId() != null, "ticket has a spot");
            assertTrue(fee == 400, "90 min at 200c/hr rounds up to 2h = 400c");
            assertTrue(lot.occupiedCount() == 0, "spot freed after unpark");
            System.out.println("Case 1 happy park+unpark, fee=" + fee + "c -> OK");
        }

        // Case 2 — best fit: a motorcycle should take a COMPACT, leaving LARGE
        // spots for cars. We park a motorcycle and confirm it landed in compact.
        {
            ParkingLotService lot = new ParkingLotService(
                buildLot(), new BestFitNearestStrategy(), () -> now[0], 200);
            Ticket moto = lot.park(new Vehicle("MOTO-1", VehicleType.MOTORCYCLE));
            assertTrue(moto.spotId().startsWith("C"), "moto took a compact spot");
            System.out.println("Case 2 best-fit moto -> " + moto.spotId() + " OK");
        }

        // Case 3 — lot full: fill every CAR-compatible (LARGE) spot, then the
        // next car must be rejected with a typed NoSpotAvailableException.
        {
            ParkingLotService lot = new ParkingLotService(
                buildLot(), new BestFitNearestStrategy(), () -> now[0], 200);
            long largeSpots = lot.availableCountFor(VehicleType.CAR);
            for (int i = 0; i < largeSpots; i++) {
                lot.park(new Vehicle("CAR-FILL-" + i, VehicleType.CAR));
            }
            boolean rejected = false;
            try {
                lot.park(new Vehicle("CAR-OVERFLOW", VehicleType.CAR));
            } catch (NoSpotAvailableException e) {
                rejected = true;
            }
            assertTrue(rejected, "overflow car rejected when lot full");
            System.out.println("Case 3 lot full rejects overflow car -> OK");
        }

        // Case 4 — unknown ticket: unparking a bad id throws a typed error.
        {
            ParkingLotService lot = new ParkingLotService(
                buildLot(), new BestFitNearestStrategy(), () -> now[0], 200);
            boolean rejected = false;
            try {
                lot.unpark("tkt-does-not-exist");
            } catch (TicketNotFoundException e) {
                rejected = true;
            }
            assertTrue(rejected, "unknown ticket rejected");
            System.out.println("Case 4 unknown ticket rejected -> OK");
        }

        // Case 5 — concurrency stampede: build a lot with exactly 5 LARGE spots,
        // fire 50 threads that all try to park a car at the same instant, and
        // prove exactly 5 win, all on DIFFERENT spots, the other 45 get the
        // typed full error. This is the double-allocation race test.
        {
            int threads = 50, capacity = 5;
            ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
                buildRaceLot(capacity), new BestFitNearestStrategy(),
                () -> now[0], 200);

            CyclicBarrier barrier = new CyclicBarrier(threads);
            AtomicInteger wins = new AtomicInteger(0);
            AtomicInteger fulls = new AtomicInteger(0);
            var wonSpots = ConcurrentHashMap.<String>newKeySet();
            ExecutorService pool = Executors.newFixedThreadPool(threads);

            for (int i = 0; i < threads; i++) {
                final int id = i;
                pool.submit(() -> {
                    try {
                        barrier.await();           // everyone starts together
                        Ticket t = lot.park(new Vehicle("C-" + id, VehicleType.CAR));
                        wins.incrementAndGet();
                        wonSpots.add(t.spotId());   // record which spot was won
                    } catch (NoSpotAvailableException e) {
                        fulls.incrementAndGet();
                    } catch (Exception e) {
                        throw new RuntimeException(e);
                    }
                });
            }
            pool.shutdown();
            assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS), "threads finished");

            assertTrue(wins.get() == capacity, "exactly 5 cars parked");
            assertTrue(wonSpots.size() == capacity, "5 DIFFERENT spots, no double-alloc");
            assertTrue(fulls.get() == threads - capacity, "45 rejected with full error");
            System.out.println("Case 5 race 50 threads -> " + wins.get()
                + " parked on " + wonSpots.size() + " distinct spots, "
                + fulls.get() + " rejected -> OK");
        }

        System.out.println("ALL CASES PASSED");
    }

    // WHY: a tiny helper instead of a JUnit assert so Main runs standalone and
    //      a failure points at the exact message and line.
    private static void assertTrue(boolean cond, String message) {
        if (!cond) {
            throw new AssertionError(message);
        }
    }

    // WHY: build a small 2-floor lot. Floor 1 and 2 each have compact, large
    //      and handicapped spots. Spot ids are prefixed by size (C/L/H) so the
    //      demo can assert which kind of spot a vehicle landed in.
    private static List<ParkingFloor> buildLot() {
        List<ParkingFloor> floors = new ArrayList<>();
        for (int f = 1; f <= 2; f++) {
            List<ParkingSpot> spots = new ArrayList<>();
            spots.add(new ParkingSpot("C" + f + "-1", f, SpotSize.COMPACT));
            spots.add(new ParkingSpot("C" + f + "-2", f, SpotSize.COMPACT));
            spots.add(new ParkingSpot("L" + f + "-1", f, SpotSize.LARGE));
            spots.add(new ParkingSpot("L" + f + "-2", f, SpotSize.LARGE));
            spots.add(new ParkingSpot("H" + f + "-1", f, SpotSize.HANDICAPPED));
            floors.add(new ParkingFloor(f, spots));
        }
        return floors;
    }

    // WHY: a lot with exactly `capacity` LARGE spots and nothing else, so the
    //      race test has a precise capacity to contend over.
    private static List<ParkingFloor> buildRaceLot(int capacity) {
        List<ParkingSpot> spots = new ArrayList<>();
        for (int i = 0; i < capacity; i++) {
            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
        }
        return List.of(new ParkingFloor(1, spots));
    }
}

package com.interview.lld.parking;

import static org.junit.jupiter.api.Assertions.assertEquals;
