import com.interview.lld.parking.strategy.BestFitNearestStrategy;

class ParkingLotServiceTest {

    // A mutable fake clock — tests move it forward to bill without sleeping.
    private final Instant[] now = { Instant.parse("2026-06-21T08:00:00Z") };
    private final Supplier<Instant> clock = () -> now[0];

    private List<ParkingFloor> buildLot() {
        List<ParkingFloor> floors = new ArrayList<>();
        for (int f = 1; f <= 2; f++) {
            List<ParkingSpot> spots = new ArrayList<>();
            spots.add(new ParkingSpot("C" + f + "-1", f, SpotSize.COMPACT));
            spots.add(new ParkingSpot("C" + f + "-2", f, SpotSize.COMPACT));
            spots.add(new ParkingSpot("L" + f + "-1", f, SpotSize.LARGE));
            spots.add(new ParkingSpot("L" + f + "-2", f, SpotSize.LARGE));
            spots.add(new ParkingSpot("H" + f + "-1", f, SpotSize.HANDICAPPED));
            floors.add(new ParkingFloor(f, spots));
        }
        return floors;
    }

    private ParkingLotService newLot() {
        return new ParkingLotService(buildLot(), new BestFitNearestStrategy(), clock, 200);
    }

    // ─── Happy path ──────────────────────────────────────────────────────────
    @Test
    void parkReturnsTicketAndOccupiesSpot() {
        ParkingLotService lot = newLot();
        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
        assertTrue(t.id().startsWith("tkt-"));
        assertEquals("CAR-1", t.vehicle().licensePlate());
        assertEquals(1, lot.occupiedCount());
    }

    @Test
    void unparkFreesSpotAndBillsRoundedUp() {
        ParkingLotService lot = newLot();
        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
        now[0] = now[0].plus(Duration.ofMinutes(90));   // 90 min -> 2 hours
        long fee = lot.unpark(t.id());
        assertEquals(400, fee, "90 min at 200c/hr rounds up to 2h");
        assertEquals(0, lot.occupiedCount());
    }

    @Test
    void shortStayBillsMinimumOneHour() {
        ParkingLotService lot = newLot();
        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
        now[0] = now[0].plus(Duration.ofMinutes(5));    // 5 min -> still 1 hour
        assertEquals(200, lot.unpark(t.id()));
    }

    // ─── Best-fit allocation ──────────────────────────────────────────────────
    @Test
    void motorcycleTakesCompactNotLarge() {
        ParkingLotService lot = newLot();
        Ticket moto = lot.park(new Vehicle("M-1", VehicleType.MOTORCYCLE));
        assertTrue(moto.spotId().startsWith("C"), "best fit puts moto in compact");
    }

    @Test
    void handicappedVehicleOnlyTakesHandicappedSpot() {
        ParkingLotService lot = newLot();
        Ticket t = lot.park(new Vehicle("H-1", VehicleType.HANDICAPPED));
        assertTrue(t.spotId().startsWith("H"), "handicapped vehicle -> handicapped spot");
    }

    @Test
    void regularCarNeverTakesHandicappedSpot() {
        // Build a lot whose ONLY free spot is handicapped; a car must be rejected.
        List<ParkingSpot> spots = new ArrayList<>();
        spots.add(new ParkingSpot("H1-1", 1, SpotSize.HANDICAPPED));
        ParkingLotService lot = new ParkingLotService(
            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);
        assertThrows(NoSpotAvailableException.class,
            () -> lot.park(new Vehicle("CAR-1", VehicleType.CAR)));
    }

    @Test
    void nearestFloorWins() {
        ParkingLotService lot = newLot();
        // First car should land on floor 1 (lower floor = nearer).
        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
        assertEquals("L1-1", t.spotId(), "lowest floor, lowest id chosen first");
    }

    // ─── Typed error paths ─────────────────────────────────────────────────────
    @Test
    void parkRejectsWhenFull() {
        ParkingLotService lot = newLot();
        long cars = lot.availableCountFor(VehicleType.CAR);
        for (int i = 0; i < cars; i++) {
            lot.park(new Vehicle("CAR-" + i, VehicleType.CAR));
        }
        assertThrows(NoSpotAvailableException.class,
            () -> lot.park(new Vehicle("OVERFLOW", VehicleType.CAR)));
    }

    @Test
    void unparkUnknownTicketThrows() {
        ParkingLotService lot = newLot();
        assertThrows(TicketNotFoundException.class, () -> lot.unpark("tkt-nope"));
    }

    @Test
    void unparkNullTicketThrows() {
        ParkingLotService lot = newLot();
        assertThrows(TicketNotFoundException.class, () -> lot.unpark(null));
    }

    @Test
    void parkNullVehicleThrows() {
        ParkingLotService lot = newLot();
        assertThrows(ParkingException.class, () -> lot.park(null));
    }

    @Test
    void blankPlateRejectedAtConstruction() {
        assertThrows(ParkingException.class, () -> new Vehicle("  ", VehicleType.CAR));
    }

    // ─── Idempotency of spot.release ───────────────────────────────────────────
    @Test
    void releaseOnFreeSpotIsNoOp() {
        ParkingSpot spot = new ParkingSpot("L1-1", 1, SpotSize.LARGE);
        spot.release();                       // releasing a free spot
        assertEquals(SpotStatus.FREE, spot.status(), "release on free spot does nothing");
        spot.occupy(new Vehicle("CAR-1", VehicleType.CAR));
        spot.release();
        spot.release();                       // second release is a safe no-op
        assertEquals(SpotStatus.FREE, spot.status());
    }

    // ─── Concurrency: the double-allocation race ───────────────────────────────
    @Test
    void concurrentParkNeverDoubleAllocatesSameSpot() throws Exception {
        int threads = 50, capacity = 5;

        // Lot with exactly `capacity` LARGE spots — the precise scarce resource.
        List<ParkingSpot> spots = new ArrayList<>();
        for (int i = 0; i < capacity; i++) {
            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
        }
        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);

        CyclicBarrier barrier = new CyclicBarrier(threads);   // stampede gate
        AtomicInteger wins = new AtomicInteger(0);
        AtomicInteger fulls = new AtomicInteger(0);
        AtomicInteger unexpected = new AtomicInteger(0);
        var wonSpots = ConcurrentHashMap.<String>newKeySet();
        ExecutorService pool = Executors.newFixedThreadPool(threads);

        for (int i = 0; i < threads; i++) {
            final int id = i;
            pool.submit(() -> {
                try {
                    barrier.await();          // all 50 hit park() at the same moment
                    Ticket t = lot.park(new Vehicle("C-" + id, VehicleType.CAR));
                    wins.incrementAndGet();
                    wonSpots.add(t.spotId());
                } catch (NoSpotAvailableException e) {
                    fulls.incrementAndGet();
                } catch (Exception e) {
                    unexpected.incrementAndGet();
                }
            });
        }
        pool.shutdown();
        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS));

        // STRICT post-state assertions:
        assertEquals(capacity, wins.get(), "exactly capacity threads parked");
        assertEquals(capacity, wonSpots.size(),
            "every win is a DIFFERENT spot — no double-allocation");
        assertEquals(threads - capacity, fulls.get(),
            "all others got the typed full error");
        assertEquals(0, unexpected.get(), "no surprise exceptions");

        // Count occupied spots via the entity status, not a service-side set.
        long occupied = spots.stream().filter(s -> s.status() == SpotStatus.OCCUPIED).count();
        assertEquals(capacity, occupied, "exactly capacity spots OCCUPIED");
        assertEquals(capacity, lot.occupiedCount(), "registry matches occupied spots");
    }

    @Test
    void concurrentParkUnparkChurnLeavesConsistentState() throws Exception {
        // Park and unpark repeatedly across many threads; the lot must end
        // empty with every spot FREE — proving no spot is leaked or stranded.
        int threads = 20;
        List<ParkingSpot> spots = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
        }
        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);

        ExecutorService pool = Executors.newFixedThreadPool(threads);
        for (int i = 0; i < threads; i++) {
            pool.submit(() -> {
                for (int r = 0; r < 50; r++) {
                    try {
                        Ticket t = lot.park(new Vehicle("X", VehicleType.CAR));
                        lot.unpark(t.id());
                    } catch (NoSpotAvailableException ignored) {
                        // lot momentarily full — fine, just retry next round
                    }
                }
            });
        }
        pool.shutdown();
        assertTrue(pool.awaitTermination(20, TimeUnit.SECONDS));

        assertEquals(0, lot.occupiedCount(), "lot empty after churn");
        long occupied = spots.stream().filter(s -> s.status() == SpotStatus.OCCUPIED).count();
        assertEquals(0, occupied, "no spot left stranded as OCCUPIED");
    }
}
